#[test]
fn test_orphans_finds_unparented() {
    let (mut storage, dir) = test_db_with_dir();
    init_test_project(&dir);

    // Create orphan issue (no parent)
    create_test_issue(&mut storage, "Orphan issue");

    // Create epic and child
    let epic_id = create_test_issue_with_type(&mut storage, "Epic", IssueType::Epic);
    let child_id = create_test_issue(&mut storage, "Child");
    set_parent(&mut storage, &child_id, &epic_id);

    let result = run_orphans_command(&dir);
    assert!(result.is_ok());
    let output = result.unwrap();
    assert!(output.contains("Orphan issue"));
    assert!(!output.contains("Child"));
}

#[test]
fn test_orphans_excludes_epics() {
    let (mut storage, dir) = test_db_with_dir();
    init_test_project(&dir);

    // Epics themselves shouldn't be counted as orphans
    create_test_issue_with_type(&mut storage, "Epic", IssueType::Epic);

    let result = run_orphans_command(&dir);
    assert!(result.is_ok());
    // Epic should not appear in orphans
}
