log_step "Verifying child not in orphans"
if echo "$ORPHANS_OUTPUT" | grep -q "$CHILD_ID"; then
    log_fail "Child issue incorrectly marked as orphan"
    exit 1
else
    log_pass "Child issue correctly excluded"
fi

log_step "Testing JSON output"
ORPHANS_JSON=$(br orphans --json)
log_debug "JSON: $ORPHANS_JSON"
echo "$ORPHANS_JSON" | jq -e '.'
log_pass "Orphans JSON valid"

log_pass "=== All orphans tests passed ==="
